-- Seed SQL Injection Knowledge Point Questions
-- Teacher ID: 2 (from system context)
-- State: 1 (enabled), Score: 10 (default)

-- ==================== 1. SQL注入（基础概念）====================
INSERT INTO t_question (question, answer, type, score, options, analysis, teacher_id, state) VALUES
('SQL注入是一种什么类型的攻击？', 'B', 2, 10, '{"A":"物理攻击","B":"代码注入攻击","C":"社会工程攻击","D":"拒绝服务攻击"}', 'SQL注入是一种代码注入技术，攻击者在输入中插入恶意SQL语句来操纵数据库。', 2, 1),
('以下哪个是SQL注入攻击的主要危害？', 'D', 2, 10, '{"A":"服务器断电","B":"网络中断","C":"显示器损坏","D":"数据库数据泄露"}', 'SQL注入攻击可导致数据库中的敏感数据泄露、被篡改或被删除。', 2, 1),
('SQL注入漏洞通常发生在哪一层？', 'C', 2, 10, '{"A":"网络层","B":"传输层","C":"应用层","D":"物理层"}', 'SQL注入发生在应用层，当应用程序将用户输入直接拼接到SQL查询中时。', 2, 1),
('Web应用程序中，SQL注入风险最高的操作是？', 'A', 2, 10, '{"A":"直接拼接SQL字符串","B":"使用参数化查询","C":"对输入进行过滤","D":"使用ORM框架"}', '直接拼接用户输入到SQL语句是最危险的做法，也是SQL注入的主要成因。', 2, 1),
('以下哪些是SQL注入的常见攻击目标？', 'A,B', 3, 10, '{"A":"用户登录验证绕过","B":"数据库数据窃取","C":"服务器CPU超频","D":"修改网络配置"}', 'SQL注入主要用于绕过认证和窃取数据库中的敏感数据。', 2, 1),
('SQL注入只能攻击MySQL数据库。', 'B', 4, 10, '{"A":"正确","B":"错误"}', 'SQL注入可以攻击任何使用SQL的数据库，包括Oracle、SQL Server、PostgreSQL等。', 2, 1),
('所有用户输入都可能导致SQL注入风险。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '任何用户输入如果未经处理就拼接到SQL语句中，都可能成为SQL注入的攻击入口。', 2, 1),
('请简述SQL注入攻击的基本原理。', 'SQL注入攻击的基本原理是攻击者在应用程序的输入字段中插入恶意的SQL代码片段，当应用程序将用户输入直接拼接到SQL查询语句中时，恶意代码随查询一起发送到数据库执行，从而达成非授权访问、数据窃取或数据篡改的目的。', 5, 15, NULL, 'SQL注入的核心是用户输入被当作SQL代码执行，而非单纯的数据。', 2, 1),

-- ==================== 2. 错误型SQL注入 ====================
('错误型SQL注入主要通过什么方式获取信息？', 'C', 2, 10, '{"A":"使用UNION查询","B":"使用时间延迟","C":"利用数据库错误信息","D":"使用布尔判断"}', '错误型SQL注入通过触发数据库返回错误信息来推断数据库结构和敏感数据。', 2, 1),
('以下哪个函数常用于错误型SQL注入？', 'D', 2, 10, '{"A":"SLEEP()","B":"BENCHMARK()","C":"IF()","D":"UPDATEXML()或EXTRACTVALUE()"}', 'UPDATEXML()和EXTRACTVALUE()等函数在被传入恶意参数时会产生包含错误信息的提示。', 2, 1),
('错误型SQL注入中，攻击者利用数据库返回的什么信息？', 'B', 2, 10, '{"A":"HTTP状态码","B":"错误消息中的数据库信息","C":"页面加载时间","D":"网络延迟"}', '数据库返回的错误消息中常包含表名、字段名等数据库结构信息，被攻击者利用。', 2, 1),
('在使用UPDATEXML()函数进行错误型注入时，如何触发错误信息？', 'A', 2, 10, '{"A":"传入格式错误的XPath表达式","B":"传入空字符串","C":"传入数字0","D":"不传任何参数"}', 'UPDATEXML()接受XPath表达式参数，传入格式错误的XPath会导致数据库返回包含有用信息的错误。', 2, 1),
('错误型注入只能用于MySQL数据库。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '各种数据库都可能存在错误信息泄露问题，不仅限于MySQL。', 2, 1),
('错误型注入属于盲注的一种。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '错误型注入不需要盲注那样的逐位推断，因为它直接通过错误消息获取信息。', 2, 1),
('简述错误型SQL注入的攻击原理。', '错误型SQL注入利用数据库在执行非法SQL操作时返回的详细错误信息。攻击者通过构造特殊的SQL语句触发数据库错误，从错误消息中解析出数据库结构、表名、字段名等敏感信息，为进一步攻击做准备。', 5, 15, NULL, '核心是利用错误信息泄露来获取数据库内部结构信息。', 2, 1),

-- ==================== 3. 联合查询注入 ====================
('联合查询注入利用SQL中的哪个关键字？', 'C', 2, 10, '{"A":"WHERE","B":"ORDER BY","C":"UNION","D":"GROUP BY"}', '联合查询注入利用UNION关键字将攻击者的查询结果合并到原查询结果中。', 2, 1),
('执行联合查询注入时，两个SELECT语句的什么必须相同？', 'A', 2, 10, '{"A":"列数","B":"表名","C":"数据类型","D":"数据库名"}', '使用UNION时，两个SELECT语句的列数必须相同，否则数据库会报错。', 2, 1),
('联合查询注入中，攻击者通常使用什么方法来确定原查询的列数？', 'B', 2, 10, '{"A":"SLEEP()延时","B":"ORDER BY子句递增测试","C":"直接猜测","D":"查看错误日志"}', '攻击者通过ORDER BY n--不断递增n的值，当n超过实际列数时报错来确定列数。', 2, 1),
('联合查询注入可以读取数据库中的哪些信息？', 'D', 2, 10, '{"A":"仅当前表数据","B":"仅当前数据库名","C":"仅当前用户","D":"当前数据库的表名、字段名和数据"}', '联合查询注入允许攻击者在同一个查询中读取数据库中的各类信息。', 2, 1),
('使用UNION联合查询时，第一个SELECT语句必须是原查询。', 'A', 4, 10, '{"A":"正确","B":"错误"}', 'UNION查询中，第一个SELECT是原查询语句，第二个SELECT是攻击者构造的查询。', 2, 1),
('联合查询注入需要页面有回显位置来显示查询结果。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '联合查询注入属于回显注入，需要页面有位置显示查询结果才能获取数据。', 2, 1),
('在进行联合查询注入时，攻击者使用information_schema数据库的目的是什么？', 'C', 2, 10, '{"A":"备份数据库","B":"优化查询性能","C":"获取所有表名和字段名","D":"创建新用户"}', 'information_schema是MySQL的系统数据库，存储了所有数据库的元数据信息，包括表名和字段名。', 2, 1),

-- ==================== 4. 布尔型盲注 ====================
('布尔型盲注通过什么来判断条件的真假？', 'A', 2, 10, '{"A":"页面返回内容的差异","B":"页面加载时间的差异","C":"HTTP响应头的差异","D":"HTTP状态码的差异"}', '布尔型盲注通过观察页面返回内容（如是否显示正常、是否包含特定字符串）来判断条件是否为真。', 2, 1),
('布尔型盲注中，常用的判断函数是？', 'C', 2, 10, '{"A":"SLEEP()","B":"BENCHMARK()","C":"SUBSTRING()和ASCII()","D":"UPDATEXML()"}', '盲注中使用SUBSTRING()和ASCII()等函数逐字符地从数据库中提取信息。', 2, 1),
('布尔型盲注与错误型注入最大的区别是什么？', 'B', 2, 10, '{"A":"攻击速度更快","B":"不依赖错误信息，只依赖页面真/假两种状态","C":"不需要数据库连接","D":"可以获取更多数据"}', '布尔型盲注不显示具体错误信息，只能通过页面"正常"或"异常"两种状态来逐位推断数据。', 2, 1),
('布尔盲注中，使用ASCII(SUBSTRING((SELECT DATABASE()),1,1))>64的作用是？', 'D', 2, 10, '{"A":"查询数据库版本","B":"检查数据库是否存在","C":"查询当前用户名","D":"判断数据库名的第一个字符的ASCII值是否大于64"}', '该语句通过二分法逐字符判断数据库名称的第一个字符的ASCII值范围，从而推断出完整数据库名。', 2, 1),
('布尔型盲注比回显注入的效率更高。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '盲注需要逐位推断数据，通常需要发送大量请求，效率远低于回显注入。', 2, 1),
('布尔型盲注中，攻击者可以通过AND或OR条件来构造判断语句。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '攻击者使用AND或OR将判断条件与原查询结合，通过页面响应来判断条件真假。', 2, 1),

-- ==================== 5. 时间型盲注 ====================
('时间型盲注通过什么来判断条件的真假？', 'C', 2, 10, '{"A":"页面内容变化","B":"HTTP状态码","C":"页面响应时间差异","D":"数据库连接数"}', '时间型盲注利用数据库的时间延迟函数（如SLEEP），如果条件为真则执行延迟，通过响应时间差异推断信息。', 2, 1),
('时间型盲注中常用的MySQL函数是？', 'B', 2, 10, '{"A":"NOW()","B":"SLEEP()","C":"CURDATE()","D":"VERSION()"}', 'SLEEP()函数可以使数据库查询暂停指定的秒数，常用于时间盲注。', 2, 1),
('当页面没有回显位置也没有错误信息显示时，攻击者应该使用哪种注入方式？', 'D', 2, 10, '{"A":"联合查询注入","B":"错误型注入","C":"布尔型盲注","D":"时间型盲注"}', '时间型盲注不依赖任何页面内容变化，只依赖响应时间，适用于无回显且无错误信息的场景。', 2, 1),
('时间型盲注中，BENCHMARK()函数的作用是？', 'A', 2, 10, '{"A":"重复执行表达式来消耗时间","B":"测量查询执行时间","C":"比较两个值的大小","D":"计算基准性能得分"}', 'BENCHMARK(count,expr)会重复执行表达式count次，消耗大量时间，用于时间盲注替代SLEEP。', 2, 1),
('时间型盲注的显著特征是？', 'C', 2, 10, '{"A":"页面内容变化","B":"页面显示错误信息","C":"页面加载明显变慢或立即返回","D":"页面发生跳转"}', '时间盲注的特征是当条件为真时页面有明显延迟，条件为假时立即返回。', 2, 1),
('时间型盲注比布尔型盲注更容易被检测和防御。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '时间型盲注会产生异常的响应延迟，更容易被WAF和安全监控系统检测到。', 2, 1),
('时间型盲注可以在没有错误信息且没有内容变化的情况下有效工作。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '时间型盲注仅依赖响应时间差异，是最隐蔽但也最慢的注入方式。', 2, 1),

-- ==================== 6. 堆叠查询注入 ====================
('堆叠查询注入使用什么字符分隔多条SQL语句？', 'B', 2, 10, '{"A":"逗号(,)","B":"分号(;)","C":"冒号(:)","D":"破折号(-)"}', '堆叠查询使用分号(;)分隔多条SQL语句，允许在同一连接中执行多个独立的SQL语句。', 2, 1),
('堆叠查询注入与联合查询注入最大的区别是？', 'A', 2, 10, '{"A":"堆叠查询可以执行增删改操作，联合查询只能查询数据","B":"堆叠查询速度更快","C":"联合查询不需要分号","D":"没有区别"}', '联合查询仅限于SELECT查询操作，而堆叠查询可以执行INSERT、UPDATE、DELETE等任意SQL操作。', 2, 1),
('PHP中哪个函数可以防止堆叠查询注入？', 'D', 2, 10, '{"A":"mysql_query()","B":"mysqli_query()","C":"PDO::query()","D":"mysqli_multi_query()的使用本身可做限制，但更安全的做法是禁止多条语句执行"}', '很多数据库API默认只允许单条语句执行，需要特殊配置才能执行多条语句，限制了堆叠查询注入。', 2, 1),
('堆叠查询注入可以执行DDL语句（如DROP TABLE）。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '堆叠查询可以执行任何SQL语句，包括DDL、DML、DCL等。', 2, 1),
('大多数MySQL驱动默认允许执行多条SQL语句。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '大多数数据库驱动和API默认禁止多条语句执行，需要通过特定参数启用。', 2, 1),
('堆叠查询注入比联合查询注入有更大的破坏力，主要原因是什么？', 'C', 2, 10, '{"A":"速度更快","B":"更容易实现","C":"可以执行修改和删除数据的操作","D":"不需要知道表名"}', '堆叠查询可以执行任意类型的SQL语句，包括破坏性的INSERT、UPDATE、DELETE和DROP操作。', 2, 1),

-- ==================== 7. 参数化查询 ====================
('参数化查询（PreparedStatement）防止SQL注入的原理是？', 'B', 2, 10, '{"A":"过滤特殊字符","B":"将SQL语句模板和数据分离，数据不会作为代码执行","C":"加密用户输入","D":"限制输入长度"}', '参数化查询将SQL语句结构（模板）与用户输入数据分离，数据仅作为值传递，不会被解释为SQL代码。', 2, 1),
('在Java中，使用什么类实现参数化查询？', 'A', 2, 10, '{"A":"PreparedStatement","B":"Statement","C":"Connection","D":"ResultSet"}', 'PreparedStatement是JDBC中用于执行预编译参数化查询的接口。', 2, 1),
('以下哪种方式可以有效防止SQL注入？', 'C', 2, 10, '{"A":"使用黑名单过滤关键字","B":"对输入进行URL编码","C":"使用参数化查询","D":"使用MD5加密输入"}', '参数化查询是目前最有效、最广泛的SQL注入防御手段，能从根本上解决SQL注入问题。', 2, 1),
('使用参数化查询后，还需要对输入进行过滤吗？', 'B', 2, 10, '{"A":"不需要，完全安全","B":"仍需做业务层面的校验","C":"反而更不安全","D":"只需要对数字类型过滤"}', '参数化查询解决了SQL注入问题，但仍需对输入进行业务逻辑层面的校验（如格式、范围等）。', 2, 1),
('参数化查询对所有SQL操作（包括ORDER BY子句）都有效。', 'B', 4, 10, '{"A":"正确","B":"错误"}', 'ORDER BY子句中的列名和排序方向不能使用参数化，需要使用白名单方式处理。', 2, 1),
('动态SQL拼接中使用参数化查询可以完全杜绝SQL注入风险。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '只要正确使用参数化查询处理所有用户输入，就可以从根本上杜绝SQL注入。', 2, 1),
('什么是参数化查询？为什么它能防御SQL注入？', '参数化查询（PreparedStatement）是预先编译SQL语句模板，将用户输入作为参数绑定而非字符串拼接的查询方式。它能防御SQL注入是因为数据库先将SQL语句编译成执行计划，此时语句结构已经固定，后续传入的参数无论包含什么内容都只会被当作纯数据处理，不会被解释为SQL代码执行。', 5, 15, NULL, '预编译 + 数据/代码分离是参数化查询安全的核心原理。', 2, 1),
('在MyBatis中，应该使用哪个标记来防止SQL注入？', 'C', 2, 10, '{"A":"${}","B":"#{}和${}都可以","C":"#{}","D":"在XML中写原生SQL"}', '#{}使用预编译参数化方式传参，而${}是直接字符串拼接，存在SQL注入风险。', 2, 1),

-- ==================== 8. ORM框架防护 ====================
('ORM框架如何帮助防御SQL注入？', 'A', 2, 10, '{"A":"自动生成参数化SQL语句","B":"加密所有数据","C":"限制查询次数","D":"自动备份数据"}', 'ORM框架（如Hibernate、MyBatis-Plus等）在内部使用参数化查询机制，自动防止SQL注入。', 2, 1),
('以下哪个ORM框架在Java生态中最常用？', 'C', 2, 10, '{"A":"Entity Framework","B":"Django ORM","C":"MyBatis和Hibernate","D":"Active Record"}', '在Java生态中，MyBatis和Hibernate是最主流的ORM框架。', 2, 1),
('使用ORM框架就绝对安全，不存在SQL注入风险。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '即使使用ORM框架，如果开发者在特殊场景下使用原生SQL查询或${}拼接，仍然可能存在SQL注入风险。', 2, 1),
('ORM框架中如果使用原生SQL查询，是否仍然存在SQL注入风险？', 'A', 2, 10, '{"A":"是，原生SQL需要手动使用参数化","B":"否，ORM自动处理一切","C":"视数据库类型而定","D":"只在使用NoSQL时有问题"}', '当ORM框架中使用原生SQL语句时，仍需手动使用参数化查询来确保安全。', 2, 1),
('MyBatis-Plus中，LambdaQueryWrapper相比普通QueryWrapper的优势之一是？', 'D', 2, 10, '{"A":"速度更快","B":"支持更多数据库","C":"自动创建索引","D":"编译期类型检查，减少SQL拼写错误和注入风险"}', 'LambdaQueryWrapper使用Lambda表达式，在编译期就能发现字段名错误，且内部使用参数化查询。', 2, 1),
('以下哪个操作在使用ORM框架时可能引入SQL注入风险？', 'B', 2, 10, '{"A":"使用实体类保存数据","B":"在@Select注解中使用${}拼接参数","C":"使用QueryWrapper查询","D":"使用Lambda表达式"}', '在注解或XML中使用${}直接拼接参数会绕过ORM的参数化保护机制，引入SQL注入风险。', 2, 1),

-- ==================== 9. 输入验证 ====================
('输入验证中，白名单验证和黑名单验证哪个更安全？', 'A', 2, 10, '{"A":"白名单验证","B":"黑名单验证","C":"两者一样安全","D":"取决于数据库类型"}', '白名单验证只允许已知的合法输入，而黑名单很难穷举所有恶意输入，因此白名单更安全。', 2, 1),
('以下哪种输入验证方式可以有效防止SQL注入？', 'D', 2, 10, '{"A":"限制输入长度","B":"删除单引号","C":"对输入进行Base64编码","D":"白名单校验结合参数化查询"}', '单一过滤方式不足以防御SQL注入，白名单校验配合参数化查询才是最有效的方案。', 2, 1),
('输入验证应该在哪一层进行？', 'C', 2, 10, '{"A":"只在客户端","B":"只在服务端","C":"客户端和服务端都需要","D":"只在数据库层"}', '客户端验证提升用户体验，服务端验证是安全底线，两者缺一不可。', 2, 1),
('仅仅过滤SQL关键字（如SELECT、DROP）就足以防御SQL注入。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '仅靠关键词黑名单过滤是不够的，攻击者可以使用编码、注释、等价函数等绕过技术。', 2, 1),
('对用户输入进行严格的格式校验（如数字字段只允许数字）可以减少SQL注入风险。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '严格的格式校验可以限制攻击面，例如数字字段只允许数字输入可完全杜绝该字段的注入风险。', 2, 1),
('以下哪项不是输入验证的常用方法？', 'D', 2, 10, '{"A":"数据类型检查","B":"长度限制","C":"格式正则校验","D":"将输入存储到文件"}', '数据类型检查、长度限制和正则校验都是常用的输入验证方法。', 2, 1),
('Web应用防火墙（WAF）可以完全替代输入验证吗？', 'B', 4, 10, '{"A":"正确","B":"错误"}', 'WAF作为辅助安全措施，不能替代应用层的输入验证，因为WAF规则可能被绕过。', 2, 1),

-- ==================== 10. 最小权限原则 ====================
('最小权限原则在数据库安全中指的是？', 'C', 2, 10, '{"A":"给所有用户管理员权限","B":"限制数据库连接数","C":"数据库账户只授予所需的最小操作权限","D":"限制数据库存储空间"}', '最小权限原则要求数据库账户只拥有完成其功能所必需的最小权限，限制攻击成功后的损害范围。', 2, 1),
('如果一个Web应用只需要读取数据，应该给数据库账户什么权限？', 'A', 2, 10, '{"A":"仅SELECT权限","B":"ALL PRIVILEGES","C":"SELECT和DROP权限","D":"SUPER权限"}', '应用只需要读取数据时，仅授予SELECT权限，避免攻击者利用该账户修改或删除数据。', 2, 1),
('最小权限原则可以限制SQL注入攻击的什么？', 'D', 2, 10, '{"A":"攻击入口","B":"攻击频率","C":"攻击检测难度","D":"攻击成功后的损害范围"}', '最小权限原则不能阻止SQL注入发生，但可以限制攻击者注入后能执行的操作范围。', 2, 1),
('生产环境中，Web应用连接数据库应该使用root账户。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '绝对禁止在生产环境中使用root账户连接数据库，应使用仅授予必要权限的专用账户。', 2, 1),
('最小权限原则也适用于操作系统和文件系统的访问控制。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '最小权限原则是安全通用的设计原则，适用于所有系统和资源的访问控制。', 2, 1),
('数据库用户权限分离的做法中，以下哪个是正确的？', 'B', 2, 10, '{"A":"所有应用共用一个数据库账户","B":"不同的应用模块使用不同的数据库账户和权限","C":"只在需要时创建账户","D":"使用默认的数据库账户"}', '权限分离策略中，不同模块使用不同权限的账户，限制单点被攻破后的影响范围。', 2, 1),

-- ==================== 11. 安全错误处理 ====================
('安全错误处理的最佳实践是？', 'D', 2, 10, '{"A":"在页面上显示详细错误信息","B":"将错误信息写入日志同时显示给用户","C":"忽略所有错误","D":"对用户隐藏数据库错误详情，仅记录日志"}', '安全错误处理要求将详细的错误信息记录在服务端日志中，只向用户显示通用错误提示。', 2, 1),
('为什么不能将数据库错误信息直接显示给用户？', 'B', 2, 10, '{"A":"会降低用户体验","B":"可能泄露数据库结构、表名等敏感信息","C":"错误信息不准确","D":"用户看不懂"}', '数据库错误消息可能包含表名、字段名、SQL语句片段等敏感信息，被攻击者利用。', 2, 1),
('生产环境中，数据库应配置为？', 'A', 2, 10, '{"A":"关闭详细错误输出","B":"开启所有错误日志","C":"显示所有警告","D":"记录每一次查询"}', '生产环境应关闭详细错误输出，避免向用户泄露内部信息。', 2, 1),
('将数据库错误信息记录到日志是安全的。', 'A', 4, 10, '{"A":"正确","B":"错误"}', '将错误详情写入服务端日志是安全的，运维人员可以通过日志排查问题而不暴露敏感信息给用户。', 2, 1),
('生产环境中开启DEBUG级别的错误显示有助于排查问题。', 'B', 4, 10, '{"A":"正确","B":"错误"}', '生产环境开启DEBUG错误显示会向用户暴露内部信息，应只在开发环境开启。', 2, 1),
('试述安全错误处理在防御SQL注入中的作用。', '安全错误处理是SQL注入防御的最后一环。即使应用存在注入漏洞，如果数据库配置为不返回详细错误信息，攻击者将无法通过错误消息获取数据库结构信息，大大增加了攻击难度。安全错误处理与参数化查询、输入验证等措施形成纵深防御体系，即使某一层被突破，后续防线仍能降低损失。', 5, 15, NULL, '错误处理是纵深防御的重要一环，与前端防御手段协同工作。', 2, 1),
('当捕获到SQL异常时，以下哪种做法是正确的？', 'C', 2, 10, '{"A":"在页面显示异常堆栈","B":"将异常堆栈写入HTML注释","C":"记录完整日志，返回通用错误信息","D":"忽略异常继续执行"}', '记录详细日志便于排查，返回通用错误信息防止敏感信息泄露，是最佳实践。', 2, 1);
